import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"47. Recall","description":"","frontmatter":{"title":"47. Recall","eba":"Biomedical Engineers 2025-2028","topics":["hours","overtime","rosters","on-call"]},"headers":[],"relativePath":"ebas/biomedical-engineers/hours-of-work/47-recall.md","filePath":"ebas/biomedical-engineers/hours-of-work/47-recall.md"}'),i={name:"ebas/biomedical-engineers/hours-of-work/47-recall.md"};function n(l,e,s,c,d,p){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_47-recall" tabindex="-1">47. Recall <a class="header-anchor" href="#_47-recall" aria-label="Permalink to &quot;47. Recall&quot;">​</a></h1><p><strong>47.1</strong> Recall – return to workplace</p><p><strong>(a)</strong> An Employee who is recalled to work during an off duty period where that work is not continuous with the next succeeding rostered period of duty will be paid overtime for a minimum of three hours pay at the overtime rate as defined in clause 46 of this Agreement.</p><p><strong>(b)</strong> An Employee recalled to work will not be required to work the full three hours if the work to be performed is completed in a shorter period.</p><p><strong>(c)</strong> Clause 47.1(a) will not apply when overtime is continuous with completion or commencement of ordinary working time.</p><p><strong>47.2</strong> Time in lieu</p><p><strong>(a)</strong> In lieu of receiving payment for overtime worked in accordance with this clause, Employees may, with the consent of the Employer, be allowed to take time off, for a period of time equivalent to the period worked in excess of ordinary rostered hours of duty, plus a period of time equivalent to the overtime penalty incurred.</p><p><strong>(b)</strong> Such time in lieu shall be taken as mutually agreed between the Employer and the Employee, provided that the accrual of such leave shall not extend beyond a 28 day period.</p><p><strong>(c)</strong> Where the leave is not taken within 28 days, such time shall be paid in accordance with this clause at the rate of pay which applied on the day the overtime was worked.</p><p><strong>47.3</strong> Recall – no return to workplace Where recall to duty can be managed without the Employee having to return to their workplace, such as by telephone, such Employee will be paid a minimum of one hour&#39;s overtime, provided that multiple recalls within a discrete hour will not attract additional payment.</p>',10)])])}const u=t(i,[["render",n]]);export{m as __pageData,u as default};
